class ClaudeAiService\n  BASE_URL = 'https://api.anthropic.com/v1'.freeze\n  \n  def initialize(api_key = nil)\n    @api_key = api_key || ENV['CLAUDE_API_KEY']\n    raise 'Claude API key not found' unless @api_key\n  end\n  \n  def detect_anomalies(network_data)\n    prompt = build_anomaly_detection_prompt(network_data)\n    \n    response = make_request('/messages', {\n      model: 'claude-3-5-sonnet-20241022',\n      max_tokens: 2000,\n      temperature: 0.1,\n      messages: [\n        {\n          role: 'user',\n          content: prompt\n        }\n      ]\n    })\n    \n    parse_anomaly_response(response)\n  rescue => e\n    Rails.logger.error \"Claude AI API error: #{e.message}\"\n    { error: e.message }\n  end\n  \n  def analyze_security_risks(security_data)\n    prompt = build_security_analysis_prompt(security_data)\n    \n    response = make_request('/messages', {\n      model: 'claude-3-5-sonnet-20241022',\n      max_tokens: 1800,\n      temperature: 0.2,\n      messages: [\n        {\n          role: 'user',\n          content: prompt\n        }\n      ]\n    })\n    \n    parse_security_response(response)\n  rescue => e\n    Rails.logger.error \"Claude AI security analysis error: #{e.message}\"\n    { error: e.message }\n  end\n  \n  private\n  \n  def make_request(endpoint, payload)\n    response = RestClient.post(\n      \"#{BASE_URL}#{endpoint}\",\n      payload.to_json,\n      {\n        'x-api-key' => @api_key,\n        'Content-Type' => 'application/json',\n        'anthropic-version' => '2023-06-01'\n      }\n    )\n    \n    JSON.parse(response.body)\n  end\n  \n  def build_anomaly_detection_prompt(data)\n    <<~PROMPT\n      As a cybersecurity expert specializing in wireless network analysis, analyze the following wardriving data for anomalies and suspicious patterns:\n      \n      Network Analysis Data:\n      #{format_network_data(data)}\n      \n      Please identify:\n      1. **Network Anomalies**: Unusual SSIDs, suspicious naming patterns, or unexpected network behaviors\n      2. **Geographic Anomalies**: Networks in unexpected locations or unusual density patterns\n      3. **Security Anomalies**: Suspicious encryption changes, unusual open networks, or potential honeypots\n      4. **Signal Anomalies**: Unexpected signal strengths, interference patterns, or coverage anomalies\n      5. **Temporal Anomalies**: Networks appearing/disappearing unexpectedly or unusual timing patterns\n      \n      For each anomaly found, please provide:\n      - Severity level (Low/Medium/High/Critical)\n      - Potential security implications\n      - Recommended investigation steps\n      - Risk assessment\n      \n      Format your response as a structured analysis with clear sections.\n    PROMPT\n  end\n  \n  def build_security_analysis_prompt(data)\n    <<~PROMPT\n      Conduct a comprehensive security assessment of the following wireless network environment:\n      \n      Security Analysis Data:\n      #{format_security_data(data)}\n      \n      Provide a detailed security assessment covering:\n      \n      1. **Vulnerability Assessment**:\n         - Open/unencrypted networks and their risks\n         - Weak encryption protocols (WEP, outdated WPA)\n         - Default or weak network names indicating poor security practices\n      \n      2. **Threat Analysis**:\n         - Potential attack vectors in the environment\n         - Networks susceptible to specific attacks (Evil Twin, etc.)\n         - Corporate vs. residential security postures\n      \n      3. **Risk Prioritization**:\n         - Critical security gaps requiring immediate attention\n         - Medium-term security improvements\n         - Long-term security strategy recommendations\n      \n      4. **Compliance & Best Practices**:\n         - Industry standard compliance gaps\n         - Security best practice violations\n         - Recommendations for security hardening\n      \n      Please provide actionable insights with specific remediation steps.\n    PROMPT\n  end\n  \n  def format_network_data(data)\n    return \"No data provided\" unless data.is_a?(Hash)\n    \n    formatted = []\n    formatted << \"Total Networks Analyzed: #{data[:total_count] || 'Unknown'}\"\n    formatted << \"Time Range: #{data[:time_range] || 'Unknown'}\"\n    formatted << \"Geographic Area: #{data[:geographic_bounds] || 'Unknown'}\"\n    \n    if data[:networks].present?\n      formatted << \"\\nSample Network Data:\"\n      data[:networks].first(15).each_with_index do |network, index|\n        formatted << \"#{index + 1}. SSID: #{network[:ssid] || 'Hidden'} | BSSID: #{network[:bssid]} | Security: #{network[:encryption]} | Signal: #{network[:signal_strength]}dBm | Location: #{network[:latitude]}, #{network[:longitude]}\"\n      end\n    end\n    \n    formatted.join(\"\\n\")\n  end\n  \n  def format_security_data(data)\n    return \"No security data provided\" unless data.is_a?(Hash)\n    \n    formatted = []\n    formatted << \"Security Overview:\"\n    formatted << \"- Total Networks: #{data[:total_networks] || 0}\"\n    formatted << \"- Open Networks: #{data[:open_networks] || 0}\"\n    formatted << \"- WEP Networks: #{data[:wep_networks] || 0}\"\n    formatted << \"- WPA/WPA2 Networks: #{data[:wpa_networks] || 0}\"\n    formatted << \"- WPA3 Networks: #{data[:wpa3_networks] || 0}\"\n    formatted << \"- Hidden Networks: #{data[:hidden_networks] || 0}\"\n    \n    if data[:vulnerability_examples].present?\n      formatted << \"\\nVulnerability Examples:\"\n      data[:vulnerability_examples].each_with_index do |vuln, index|\n        formatted << \"#{index + 1}. #{vuln[:description]} (Severity: #{vuln[:severity]})\"\n      end\n    end\n    \n    formatted.join(\"\\n\")\n  end\n  \n  def parse_anomaly_response(response)\n    content = response.dig('content', 0, 'text')\n    {\n      anomalies: content,\n      model_used: response['model'],\n      analysis_type: 'anomaly_detection',\n      timestamp: Time.current\n    }\n  end\n  \n  def parse_security_response(response)\n    content = response.dig('content', 0, 'text')\n    {\n      security_analysis: content,\n      model_used: response['model'],\n      analysis_type: 'security_assessment',\n      timestamp: Time.current\n    }\n  end\nend
